CREATE TABLE HNM_セキュリティ取引相手先(     取引相手先ＳＥＱコード      CHAR(5)            NOT NULL,    有効開始日                  DATE               NOT NULL,    業務区分                    CHAR(8)            NOT NULL,    取引相手先コード            CHAR(6)            NOT NULL,    取引相手先名                VARCHAR2(100)      NOT NULL,    取引相手先名＿カナ          VARCHAR2(50)       NOT NULL,    取引相手先名＿略称          VARCHAR2(40)       NOT NULL,    有効終了日                  DATE               NOT NULL,    最終更新日時                DATE               NOT NULL,    最終更新氏名コード          CHAR(7)            NOT NULL,     CONSTRAINT HNM002_PK PRIMARY KEY(取引相手先ＳＥＱコード)         USING INDEX NOLOGGING PCTFREE 10 INITRANS 2 MAXTRANS 255             TABLESPACE USERTBS1             STORAGE(INITIAL 1M NEXT 1M MINEXTENTS 1 MAXEXTENTS UNLIMITED PCTINCREASE 5                  FREELISTS 1 FREELIST GROUPS 1 BUFFER_POOL DEFAULT ) )